Stack<int> stack = new Stack<int>();
stack.Push(1);
stack.Push(2);

// 增加（Push）
stack.Push(3);

// 删除（Pop）并返回栈顶元素
int topNumber = stack.Pop();

// 修改（Stack不支持直接修改元素，需先Pop再Push）
int poppedValue = stack.Pop();
// 替换刚弹出的值
stack.Push(poppedValue * 2); 

// 查询（Peek / Contains） 但不移除栈顶元素
int peekedValue = stack.Peek();
